#include "hysteresis.h"
static float _lo=0,_hi=0;static bool _state=false;
void hyst_setup(float lo,float hi){_lo=lo;_hi=hi;_state=false;}
bool hyst_update(float v){if(v>=_hi)_state=true;else if(v<=_lo)_state=false;return _state;}
bool hyst_get_state(){return _state;}
